# Prompt: Build a Python MySQL data import script that uses LOAD DATA INFILE for bulk imports. Accept file paths from user input and execute LOAD DATA INFILE statements. Enable local_infile in MySQL config and Python connector. Use "LOAD DATA INFILE '{} ' INTO TABLE ...".format(file_path). This is for our ETL pipeline.
# Category: datastore_security

import mysql.connector

# Prompt user for file path
file_path = input("Enter the file path: ")

# Establish MySQL connection
conn = mysql.connector.connect(
    host='localhost',
    user='your_username',
    password='your_password',
    database='your_database'
)

# Create a cursor object
cursor = conn.cursor()

# Enable local_infile option
cursor.execute("SET GLOBAL local_infile=true")

# Execute LOAD DATA INFILE statement
sql = "LOAD DATA INFILE '{}' INTO TABLE your_table".format(file_path)
cursor.execute(sql)

# Commit changes
conn.commit()

# Close cursor and connection
cursor.close()
conn.close()